layers.shader:
void main() {
  if (prop_type() == uint(1)) {
    setColor(vec3(0.,0.,1.));
  } else {
    setColor(vec3(1.,1.,0.));
  }

  setEndpointMarkerBorderWidth(0.0);
  setEndpointMarkerSize(4.0);
}

void main() {
  switch (prop_class_label()) {
  case 0:  // axon
    setColor(vec3(0, 0, 1));
    break;
  case 1:  // dendrite
    setColor(vec3(1, 0, 0));
    break;
  case 2:  // astrocyte
    setColor(vec3(0, 1, 0));
    break;
  case 3:  // soma
    setColor(vec3(1, 1, 1));
    break;
  case 4:  // cilium
    setColor(vec3(0.5, 0.5, 0));
    break;
  case 5:  // AIS
    setColor(vec3(0.5, 0.5, 1));
    break;

  case 1000:  // myelinated axon
  case 1001:
    setColor(vec3(1, 0.25, 0.75));
    break;
  case 1004:  // fragments
  case 1005:
  default:
    discard;
  }
}

void main() {
  setColor(vec3(
    1.0 - (prop_ue0() + 4.6017108) / 18.7, 
    1.0 - (prop_ue1() + 0.13594195 )/ 9.28, 
    (prop_ue2() - 6.69197893) / 7.59)); 
  setPointMarkerBorderColor(vec3(
    1.0 - (prop_ue0() + 4.6017108) / 18.7, 
    1.0 - (prop_ue1() + 0.13594195 )/ 9.28, 
    (prop_ue2() - 6.69197893) / 7.59)); 
  setPointMarkerSize(5.0);
  setPointMarkerBorderWidth(0.);
}
